import React, { Component } from 'react';
import './index.css';
import Navbar from '../../components/Navbar';
// import Footer from '../../components/Footer';


class Projects extends Component {
    render() {
        return (
            <div>
                <Navbar />
                <br />
                <div className="container text-light bg-primary-muted">
                    <div className="row border border-light radius-20">
                        <div className="col-3 border bg-dark" style={{marginTop: '15px'}}>                            
                            <p className="text-silt text-center text-large">Projects</p>
                        </div>
                        <div className="col-9 text-center">
                            <p className="text-silt border bg-dark">
                                Sort by...
                            </p>
                            <div className="row bg-dark">
                                <div className="col border border-primary">                            
                                    {/* <input type="checkbox"/> */}
                                    <span>Newest</span>
                                </div>
                                <div className="col border">                            
                                    {/* <input type="checkbox"/> */}
                                    <span>Oldest</span>
                                </div>
                                <div className="col border">                            
                                    {/* <input type="checkbox"/> */}
                                    <span>Games</span>
                                </div>
                                <div className="col border">                            
                                    <span>A-Z</span>
                                </div>
                            </div>
                        </div>                        
                    </div>                         
                </div>
                {/* <Footer /> */}
            </div>
        )
    }
}

export default Projects;